#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\"\"\"\nМиграция apteki.json от v1.0.9 к v1.10.0\n\nДобавляет поле vne_ip в каждое подразделение\nЕсли vne_ip уже существует, не перезаписывает\n\"\"\"\n\nimport json\nfrom pathlib import Path\nfrom datetime import datetime\nfrom typing import List, Dict\n\ndef migrate_apteki_json(file_path: str = \"apteki.json\", backup: bool = True) -> bool:\n    \"\"\"\n    Добавить поле vne_ip в файл apteki.json\n    \n    Args:\n        file_path: путь к файлу apteki.json\n        backup: создать ли резервную копию перед миграцией\n    \n    Returns:\n        True если успешно, False если ошибка\n    \"\"\"\n    \n    file_path = Path(file_path)\n    \n    # Проверка существования файла\n    if not file_path.exists():\n        print(f\"❌ Файл {file_path} не найден\")\n        return False\n    \n    # Создание резервной копии\n    if backup:\n        backup_path = file_path.with_stem(file_path.stem + \"_backup_\" + datetime.now().strftime(\"%Y%m%d_%H%M%S\"))\n        try:\n            backup_path.write_text(file_path.read_text(encoding='utf-8'), encoding='utf-8')\n            print(f\"✓ Резервная копия создана: {backup_path}\")\n        except Exception as e:\n            print(f\"⚠ Не удалось создать резервную копию: {e}\")\n            return False\n    \n    # Загрузка JSON\n    try:\n        with open(file_path, 'r', encoding='utf-8') as f:\n            data = json.load(f)\n    except json.JSONDecodeError as e:\n        print(f\"❌ Ошибка при чтении JSON: {e}\")\n        return False\n    except Exception as e:\n        print(f\"❌ Ошибка при открытии файла: {e}\")\n        return False\n    \n    # Обработка данных\n    if isinstance(data, list):\n        branches = data\n    elif isinstance(data, dict) and 'branches' in data:\n        branches = data['branches']\n    else:\n        print(\"❌ Неподдерживаемая структура JSON\")\n        return False\n    \n    if not isinstance(branches, list):\n        print(\"❌ Данные не являются списком подразделений\")\n        return False\n    \n    # Миграция\n    updated_count = 0\n    missing_vne_ip = []\n    \n    for i, branch in enumerate(branches):\n        if not isinstance(branch, dict):\n            print(f\"⚠ Строка {i+1}: не словарь, пропущена\")\n            continue\n        \n        prefix = branch.get('prefix', f'unknown_{i}')\n        name = branch.get('name', 'Unknown')\n        \n        # Если vne_ip уже существует, не трогаем\n        if 'vne_ip' in branch:\n            if branch['vne_ip']:\n                print(f\"  ✓ Префикс {prefix}: {name} - уже имеет vne_ip ({branch['vne_ip']})\")\n            else:\n                print(f\"  ⚠ Префикс {prefix}: {name} - vne_ip пусто, требуется заполнить\")\n                missing_vne_ip.append({'index': i+1, 'prefix': prefix, 'name': name})\n            continue\n        \n        # Пытаемся определить vne_ip автоматически (если есть какая-то логика)\n        # В большинстве случаев vne_ip нужно заполнить вручную\n        \n        # Добавляем пустой vne_ip для заполнения\n        branch['vne_ip'] = \"\"\n        updated_count += 1\n        missing_vne_ip.append({'index': i+1, 'prefix': prefix, 'name': name})\n        print(f\"  ⊕ Префикс {prefix}: {name} - добавлено пустое поле vne_ip\")\n    \n    # Сохранение обновленного JSON\n    try:\n        if isinstance(data, dict):\n            data['branches'] = branches\n        \n        with open(file_path, 'w', encoding='utf-8') as f:\n            json.dump(data, f, ensure_ascii=False, indent=2)\n        \n        print(f\"\\n✓ Файл {file_path} успешно обновлён\")\n        print(f\"  • Добавлено/обновлено полей vne_ip: {updated_count}\")\n        \n    except Exception as e:\n        print(f\"❌ Ошибка при сохранении файла: {e}\")\n        return False\n    \n    # Вывод информации о пропущенных полях\n    if missing_vne_ip:\n        print(f\"\\n⚠ ТРЕБУЕТСЯ ЗАПОЛНИТЬ {len(missing_vne_ip)} ВНЕШНИХ IP-АДРЕСОВ:\")\n        print(\"\\n  Шаблон для редактирования apteki.json:\\n\")\n        \n        for item in missing_vne_ip:\n            print(f\"  Строка {item['index']} (Префикс {item['prefix']})\")\n            print(f\"  Имя: {item['name']}\")\n            print(f\"  Добавить: \\\"vne_ip\\\": \\\"<внешний_IP>\\\"\")\n            print()\n    \n    return True\n\ndef show_vne_ip_status(file_path: str = \"apteki.json\") -> None:\n    \"\"\"\n    Показать статус заполнения поля vne_ip\n    \"\"\"\n    \n    file_path = Path(file_path)\n    \n    if not file_path.exists():\n        print(f\"❌ Файл {file_path} не найден\")\n        return\n    \n    try:\n        with open(file_path, 'r', encoding='utf-8') as f:\n            data = json.load(f)\n    except Exception as e:\n        print(f\"❌ Ошибка при чтении файла: {e}\")\n        return\n    \n    if isinstance(data, list):\n        branches = data\n    elif isinstance(data, dict) and 'branches' in data:\n        branches = data['branches']\n    else:\n        print(\"❌ Неподдерживаемая структура JSON\")\n        return\n    \n    total = len(branches)\n    with_vne_ip = sum(1 for b in branches if isinstance(b, dict) and b.get('vne_ip'))\n    without_vne_ip = sum(1 for b in branches if isinstance(b, dict) and not b.get('vne_ip'))\n    no_field = sum(1 for b in branches if isinstance(b, dict) and 'vne_ip' not in b)\n    \n    print(f\"\\nСтатус поля vne_ip в {file_path}:\")\n    print(f\"  📊 Всего подразделений: {total}\")\n    print(f\"  ✓ С заполненным vne_ip: {with_vne_ip}\")\n    print(f\"  ⚠ Без vne_ip: {without_vne_ip}\")\n    print(f\"  ⊕ Поле не существует: {no_field}\")\n    \n    if without_vne_ip > 0 or no_field > 0:\n        print(f\"\\n🔴 ТРЕБУЕТСЯ ДЕЙСТВИЕ: {without_vne_ip + no_field} подразделений нужно обновить\")\n    else:\n        print(f\"\\n🟢 ВСЕ ПОДРАЗДЕЛЕНИЯ ГОТОВЫ К ВЕРСИИ 1.10.0\")\n\nif __name__ == \"__main__\":\n    print(\"═\" * 70)\n    print(\"Миграция apteki.json: добавление поля vne_ip (версия 1.10.0)\")\n    print(\"═\" * 70)\n    \n    # Сначала показываем статус\n    show_vne_ip_status()\n    \n    # Затем выполняем миграцию\n    print(\"\\n\" + \"─\" * 70)\n    print(\"Начинаю миграцию...\\n\")\n    \n    success = migrate_apteki_json()\n    \n    # Показываем финальный статус\n    print(\"\\n\" + \"─\" * 70)\n    print(\"Финальный статус:\\n\")\n    show_vne_ip_status()\n    \n    if success:\n        print(\"\\n✓ Миграция завершена успешно\")\n        print(\"\\nСледующие шаги:\")\n        print(\"1. Откройте apteki.json в текстовом редакторе\")\n        print(\"2. Заполните поле \\\"vne_ip\\\" для каждого подразделения\")\n        print(\"3. Сохраните файл\")\n        print(\"4. Перезагрузите приложение Distributor\")\n    else:\n        print(\"\\n❌ Миграция не удалась\")\n    \n    print(\"\\n\" + \"═\" * 70)\n